## The Deobfuscated Result

```javascript
var TAU = 6.283;        // 2π (full circle in radians)
var PHI = 1.618;        // Golden ratio
var INV_SQRT2 = 0.707;  // 1/√2

var config = {
  combustion: 4000,      // Repulsion strength between nodes
  frictionCoeff: 0.004,  // Spring default stiffness
  communication: 0.92,   // Velocity damping factor
  dispersal: 0.0003,     // Gravity toward center strength
  streamMax: 40,         // Max number of particles
  streamDecay: 0.04,     // Particle friction/decay rate
  theta: 0.06            // Lens interpolation speed
};

// "edges" are actually the NODES (vertices) of the graph
var edges = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// "nodes" are actually the EDGES (links/springs) of the graph
var nodes = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var lens  = { x: 400, y: 300, zoom: 1 };  // Current camera
var focus = { x: 400, y: 300, zoom: 1 };  // Target camera
var stream = [];  // Particle array
var cycle = 0;

function edgeById(id) {
  for (var i = 0; i < edges.length; i++) {
    if (edges[i].id === id) return edges[i];
  }
  return null;
}

// Force-directed graph physics
function converge() {
  // 1) Repulsion between all node pairs (Coulomb's law)
  for (var i = 0; i < edges.length; i++) {
    for (var j = i + 1; j < edges.length; j++) {
      var dx = edges[i].x - edges[j].x;
      var dy = edges[i].y - edges[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.combustion / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      edges[i].vx += fx;
      edges[i].vy += fy;
      edges[j].vx -= fx;
      edges[j].vy -= fy;
    }
  }

  // 2) Spring attraction along links (Hooke's law)
  for (var i = 0; i < nodes.length; i++) {
    var nodeA = edgeById(nodes[i].a);
    var nodeB = edgeById(nodes[i].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - nodes[i].rest;
    var force = (nodes[i].k || config.frictionCoeff) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) Gentle gravity toward center (400, 300) + velocity damping + position update
  for (var i = 0; i < edges.length; i++) {
    edges[i].vx += (400 - edges[i].x) * config.dispersal;
    edges[i].vy += (300 - edges[i].y) * config.dispersal;
    edges[i].vx *= config.communication;  // damping (0.92)
    edges[i].vy *= config.communication;
    edges[i].x += edges[i].vx;
    edges[i].y += edges[i].vy;
  }
}

// Spawn a particle from a random node
function emitStream() {
  if (stream.length >= config.streamMax) return;
  var source = edges[Math.floor(Math.random() * edges.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * INV_SQRT2;
  stream.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * INV_SQRT2
  });
}

// Update and cull particles
function decayStream() {
  for (var i = stream.length - 1; i >= 0; i--) {
    var p = stream[i];
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) stream.splice(i, 1);
  }
}

// Smooth camera interpolation
function adjustLens() {
  lens.x += (focus.x - lens.x) * config.theta;
  lens.y += (focus.y - lens.y) * config.theta;
  lens.zoom += (focus.zoom - lens.zoom) * config.theta;
}

// Main loop
function pulse() {
  converge();      // Physics step
  if (cycle % 3 === 0) emitStream();  // Emit particle every 3rd frame
  decayStream();   // Update particles
  adjustLens();    // Smooth camera
  cycle++;
}

setInterval(pulse, 16);  // ~60 FPS
```

## What It Does

This is a **force-directed graph simulation** with a particle system, running at ~60 FPS. Specifically:

1. **Force-directed layout**: 6 labeled nodes (Hub, Alpha, Beta, Gamma, Delta, Epsilon) connected by 8 spring links. Each tick applies:
   - **Repulsion** (inverse-square, like electric charges) pushing all nodes apart
   - **Spring attraction** (Hooke's law) pulling connected nodes toward their rest lengths
   - **Gravity** gently pulling everything toward center (400, 300)
   - **Velocity damping** (0.92× per frame) to prevent explosion

2. **Particle stream**: Every 3 frames, a particle spawns at a random node, drifts outward in a random direction, slowly decelerates, and dies after 800–2000 frames.

3. **Camera system**: A `lens` smoothly interpolates toward a `focus` target (for panning/zooming), though both start at the same position.

> **Note the intentionally swapped naming**: the code calls its **vertices** `edges` and its **links** `nodes` — likely as an additional obfuscation/confusion tactic. This is purely a simulation engine with **no rendering code included** — it would need a canvas/SVG renderer to visualize anything.
